import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import api from '../services/api';

const Registro = () => {
  const navigate = useNavigate();
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [success, setSuccess] = useState('');
  const [tiposDocumento, setTiposDocumento] = useState([]);
  const [coordinadores, setCoordinadores] = useState([]);

  const [formData, setFormData] = useState({
    nombreUsuario: '',
    tipoIdentificacion: '',
    numeroIdentificacion: '',
    nombre: '',
    apellido: '',
    telefono: '',
    correoElectronico: '',
    coordinadorAsignado: '',
    password: '',
    confirmPassword: ''
  });

  useEffect(() => {
    cargarDatosIniciales();
  }, []);

  const cargarDatosIniciales = async () => {
    try {
      const [tiposRes, coordinadoresRes] = await Promise.all([
        api.get('/tipos-documento'),
        api.get('/coordinadores')
      ]);
      setTiposDocumento(tiposRes.data.data || []);
      setCoordinadores(coordinadoresRes.data.data || []);
    } catch (error) {
      console.error('Error cargando datos:', error);
    }
  };

  const handleChange = (e) => {
    setFormData({ ...formData, [e.target.name]: e.target.value });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError('');
    setSuccess('');
    setLoading(true);

    try {
      if (!formData.nombreUsuario) throw new Error('El nombre de usuario es obligatorio');
      if (!formData.tipoIdentificacion) throw new Error('Seleccione un tipo de identificación');
      if (!formData.numeroIdentificacion) throw new Error('El número de identificación es obligatorio');
      if (!formData.nombre) throw new Error('El nombre es obligatorio');
      if (!formData.apellido) throw new Error('El apellido es obligatorio');
      if (!formData.telefono) throw new Error('El teléfono es obligatorio');
      if (!formData.correoElectronico) throw new Error('El correo es obligatorio');
      if (!formData.coordinadorAsignado) throw new Error('Seleccione un coordinador');
      if (!formData.password) throw new Error('La contraseña es obligatoria');
      if (formData.password !== formData.confirmPassword) throw new Error('Las contraseñas no coinciden');
      if (formData.password.length < 6) throw new Error('La contraseña debe tener al menos 6 caracteres');

      const emailRegex = /^\w+([.-]?\w+)*@\w+([.-]?\w+)*(\.\w{2,3})+$/;
      if (!emailRegex.test(formData.correoElectronico)) throw new Error('Correo electrónico inválido');

      const { confirmPassword, ...datosEnvio } = formData;
      await api.post('/auth/register', datosEnvio);

      setSuccess('¡Registro exitoso! Redirigiendo al login...');
      setTimeout(() => navigate('/login'), 2000);
    } catch (error) {
      console.error('Error:', error);
      setError(error.response?.data?.message || error.message);
    } finally {
      setLoading(false);
    }
  };

  return (
    <>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Sora:wght@300;400;500;600&display=swap');

        .r-page {
          font-family: 'Sora', sans-serif;
          background: #f4f7f5;
          min-height: 100vh;
          display: flex;
          align-items: flex-start;
          justify-content: center;
          padding: 40px 24px;
          box-sizing: border-box;
        }

        .r-card {
          background: #ffffff;
          border: 1px solid #e0ebe4;
          border-radius: 20px;
          width: 100%;
          max-width: 580px;
          padding: 44px 40px;
          position: relative;
          overflow: hidden;
          box-sizing: border-box;
        }

        .r-card::before {
          content: '';
          position: absolute;
          top: -1px;
          left: 50%;
          transform: translateX(-50%);
          width: 160px;
          height: 3px;
          background: #00643C;
          border-radius: 0 0 4px 4px;
        }

        .r-top {
          display: flex;
          align-items: center;
          justify-content: space-between;
          margin-bottom: 32px;
        }

        .r-logo {
          background: #00643C;
          border-radius: 10px;
          padding: 8px 14px;
          font-size: 15px;
          font-weight: 600;
          color: white;
          letter-spacing: 2px;
        }

        .r-badge {
          font-size: 11px;
          color: #7a8f82;
          background: #f0f7f3;
          border: 1px solid #dce8e1;
          border-radius: 20px;
          padding: 4px 12px;
          font-weight: 500;
        }

        .r-heading {
          font-size: 20px;
          font-weight: 600;
          color: #111;
          margin: 0 0 4px 0;
        }

        .r-sub {
          font-size: 13px;
          color: #7a8f82;
          margin: 0 0 28px 0;
        }

        .r-section {
          font-size: 10px;
          font-weight: 600;
          letter-spacing: 1.5px;
          text-transform: uppercase;
          color: #00643C;
          margin: 20px 0 14px 0;
          display: flex;
          align-items: center;
          gap: 8px;
        }

        .r-section::after {
          content: '';
          flex: 1;
          height: 1px;
          background: #e8f0eb;
        }

        .r-row {
          display: flex;
          gap: 14px;
          margin-bottom: 14px;
        }

        .r-half { flex: 1; }

        .r-full {
          width: 100%;
          margin-bottom: 14px;
        }

        .r-label {
          display: block;
          font-size: 11px;
          font-weight: 500;
          letter-spacing: 0.8px;
          text-transform: uppercase;
          color: #7a8f82;
          margin-bottom: 6px;
        }

        .r-input,
        .r-select {
          width: 100%;
          padding: 11px 14px;
          background: #f8faf9;
          border: 1px solid #dce8e1;
          border-radius: 10px;
          font-size: 13px;
          font-family: 'Sora', sans-serif;
          color: #111;
          outline: none;
          box-sizing: border-box;
          transition: border-color 0.2s, box-shadow 0.2s, background 0.2s;
        }

        .r-input::placeholder { color: #b8ccc0; }

        .r-input:focus,
        .r-select:focus {
          border-color: #00643C;
          background: white;
          box-shadow: 0 0 0 3px rgba(0,100,60,0.08);
        }

        .r-select { appearance: none; cursor: pointer; }

        .r-error {
          background: #fef2f2;
          border: 1px solid #fca5a5;
          border-radius: 8px;
          padding: 10px 14px;
          font-size: 13px;
          color: #b91c1c;
          margin-bottom: 16px;
        }

        .r-success {
          background: #f0fdf4;
          border: 1px solid #86efac;
          border-radius: 8px;
          padding: 10px 14px;
          font-size: 13px;
          color: #166534;
          margin-bottom: 16px;
        }

        .r-btn-row {
          display: flex;
          gap: 12px;
          margin-top: 28px;
        }

        .r-btn-primary {
          flex: 2;
          padding: 13px;
          background: #00643C;
          color: white;
          border: none;
          border-radius: 10px;
          font-size: 14px;
          font-weight: 600;
          font-family: 'Sora', sans-serif;
          cursor: pointer;
          transition: background 0.2s, transform 0.1s;
        }

        .r-btn-primary:hover:not(:disabled) { background: #004d2e; }
        .r-btn-primary:active:not(:disabled) { transform: scale(0.99); }

        .r-btn-primary:disabled {
          background: #a3c4b5;
          cursor: not-allowed;
        }

        .r-btn-secondary {
          flex: 1;
          padding: 13px;
          background: transparent;
          color: #00643C;
          border: 1px solid #dce8e1;
          border-radius: 10px;
          font-size: 14px;
          font-weight: 500;
          font-family: 'Sora', sans-serif;
          cursor: pointer;
          transition: background 0.2s;
        }

        .r-btn-secondary:hover { background: #f0f7f3; }

        .r-footer {
          margin-top: 28px;
          padding-top: 18px;
          border-top: 1px solid #e8f0eb;
          text-align: center;
          font-size: 11px;
          color: #b8ccc0;
          letter-spacing: 0.3px;
        }

        @media (max-width: 560px) {
          .r-card { padding: 36px 20px; }
          .r-row { flex-direction: column; gap: 0; }
          .r-half { margin-bottom: 14px; }
          .r-btn-row { flex-direction: column; }
        }
      `}</style>

      <div className="r-page">
        <div className="r-card">

          <div className="r-top">
            <div className="r-logo">SENA</div>
            <div className="r-badge">Registro de usuario</div>
          </div>

          <h2 className="r-heading">Crea tu cuenta</h2>
          <p className="r-sub">Completa los datos para registrarte en la plataforma.</p>

          {error && <div className="r-error">{error}</div>}
          {success && <div className="r-success">{success}</div>}

          <form onSubmit={handleSubmit}>

            {/* ── Información de acceso ── */}
            <div className="r-section">Información de acceso</div>

            <div className="r-full">
              <label className="r-label">Nombre de usuario</label>
              <input
                className="r-input"
                type="text"
                name="nombreUsuario"
                value={formData.nombreUsuario}
                onChange={handleChange}
                placeholder="ej: juan.perez"
                required
              />
            </div>

            <div className="r-row">
              <div className="r-half">
                <label className="r-label">Contraseña</label>
                <input
                  className="r-input"
                  type="password"
                  name="password"
                  value={formData.password}
                  onChange={handleChange}
                  placeholder="••••••••"
                  required
                />
              </div>
              <div className="r-half">
                <label className="r-label">Confirmar contraseña</label>
                <input
                  className="r-input"
                  type="password"
                  name="confirmPassword"
                  value={formData.confirmPassword}
                  onChange={handleChange}
                  placeholder="••••••••"
                  required
                />
              </div>
            </div>

            {/* ── Datos personales ── */}
            <div className="r-section">Datos personales</div>

            <div className="r-row">
              <div className="r-half">
                <label className="r-label">Nombres</label>
                <input
                  className="r-input"
                  type="text"
                  name="nombre"
                  value={formData.nombre}
                  onChange={handleChange}
                  placeholder="Juan Carlos"
                  required
                />
              </div>
              <div className="r-half">
                <label className="r-label">Apellidos</label>
                <input
                  className="r-input"
                  type="text"
                  name="apellido"
                  value={formData.apellido}
                  onChange={handleChange}
                  placeholder="Pérez González"
                  required
                />
              </div>
            </div>

            <div className="r-row">
              <div className="r-half">
                <label className="r-label">Tipo de identificación</label>
                <select
                  className="r-select"
                  name="tipoIdentificacion"
                  value={formData.tipoIdentificacion}
                  onChange={handleChange}
                  required
                >
                  <option value="">Seleccione...</option>
                  {tiposDocumento.map(tipo => (
                    <option key={tipo._id} value={tipo._id}>{tipo.nombre}</option>
                  ))}
                </select>
              </div>
              <div className="r-half">
                <label className="r-label">Número de identificación</label>
                <input
                  className="r-input"
                  type="text"
                  name="numeroIdentificacion"
                  value={formData.numeroIdentificacion}
                  onChange={handleChange}
                  placeholder="123456789"
                  required
                />
              </div>
            </div>

            <div className="r-row">
              <div className="r-half">
                <label className="r-label">Correo electrónico</label>
                <input
                  className="r-input"
                  type="email"
                  name="correoElectronico"
                  value={formData.correoElectronico}
                  onChange={handleChange}
                  placeholder="correo@sena.edu.co"
                  required
                />
              </div>
              <div className="r-half">
                <label className="r-label">Teléfono</label>
                <input
                  className="r-input"
                  type="tel"
                  name="telefono"
                  value={formData.telefono}
                  onChange={handleChange}
                  placeholder="3001234567"
                  required
                />
              </div>
            </div>

            {/* ── Asignación ── */}
            <div className="r-section">Asignación</div>

            <div className="r-full">
              <label className="r-label">Coordinador asignado</label>
              <select
                className="r-select"
                name="coordinadorAsignado"
                value={formData.coordinadorAsignado}
                onChange={handleChange}
                required
              >
                <option value="">Seleccione un coordinador...</option>
                {coordinadores.map(coord => (
                  <option key={coord._id} value={coord._id}>{coord.nombre}</option>
                ))}
              </select>
            </div>

            <div className="r-btn-row">
              <button
                type="submit"
                className="r-btn-primary"
                disabled={loading}
              >
                {loading ? 'Registrando...' : 'Registrarse'}
              </button>
              <button
                type="button"
                className="r-btn-secondary"
                onClick={() => navigate('/login')}
              >
                Volver al login
              </button>
            </div>

          </form>

          <div className="r-footer">
            © 2025 SENA · Servicio Nacional de Aprendizaje
          </div>

        </div>
      </div>
    </>
  );
};

export default Registro;
